#!/usr/bin/env python3
"""
Regenerate the Whisper *decoder* parity fixtures.

Companion to ``regenerate-mel-fixtures.py``. Reads the existing
``parity-input.wav`` (so the audio-side reference does not drift), runs
the HuggingFace ``openai/whisper-tiny`` model end-to-end, and dumps the
intermediate tensors needed to validate the Pneuma Rust decoder against
HF without re-running our own encoder.

Outputs (all in this fixtures directory):

  parity-encoder-out.f32           HF encoder hidden state
                                   ``(n_audio_ctx=1500, d_model=384)`` row-major,
                                   raw f32 little-endian. Same orientation the
                                   Rust ``WhisperEncoder::forward`` returns and
                                   the same input ``WhisperDecoder::prepare_audio_context``
                                   expects.

  parity-decoder-tokens.u32        First 32 generated token IDs from greedy
                                   decode (no sampling, num_beams=1), as raw
                                   little-endian u32. Includes the standard
                                   forced prefix ``<|startoftranscript|>
                                   <|en|> <|transcribe|> <|notimestamps|>``
                                   so the smoke test can replay the same
                                   prefix and start argmax-comparing from the
                                   first *generated* slot.

  parity-decoder-step0-logits.f32  Logits from the decoder at step 0 (the
                                   ``<|startoftranscript|>`` slot, conditioned
                                   on the encoder output). Vocab-size float32
                                   array, raw LE.

Run:
  /path/to/buleyean-rl/.venv/bin/python \
    open-source/gnosis/distributed-inference-host/__tests__/fixtures/regenerate-decoder-fixtures.py

PASS bar for the Rust decoder (see pneuma-smoke-decoder-parity binary):
cosine similarity > 0.99 between HF step-0 logits and ours.
"""
import sys
from pathlib import Path

try:
    import numpy as np
    import soundfile as sf
    import torch
    from transformers import (
        WhisperForConditionalGeneration,
        WhisperProcessor,
    )
except ImportError as e:
    sys.exit(f"install: pip install transformers torch soundfile numpy ({e})")

OUT = Path(__file__).parent
WAV = OUT / "parity-input.wav"
ENC_REF = OUT / "parity-encoder-out.f32"
TOKENS_REF = OUT / "parity-decoder-tokens.u32"
LOGITS_REF = OUT / "parity-decoder-step0-logits.f32"

if not WAV.exists():
    sys.exit(f"missing {WAV} -- run regenerate-mel-fixtures.py first")

MODEL_ID = "openai/whisper-tiny"
N_GENERATED_TOKENS = 32

# ── 1. Load audio, run feature extractor ──────────────────────────────────
audio, sr = sf.read(str(WAV))
if audio.ndim > 1:
    audio = audio.mean(axis=1)
audio = audio.astype(np.float32)
print(f"loaded audio: {audio.shape} @ {sr} Hz, peak={float(np.abs(audio).max()):.3f}")

processor = WhisperProcessor.from_pretrained(MODEL_ID)
inputs = processor(audio, sampling_rate=16000, return_tensors="pt")
input_features = inputs["input_features"]  # (1, 80, 3000)
print(f"input_features: {tuple(input_features.shape)} dtype={input_features.dtype}")

# ── 2. Load model, run encoder ────────────────────────────────────────────
model = WhisperForConditionalGeneration.from_pretrained(MODEL_ID)
model.eval()

with torch.no_grad():
    encoder_outputs = model.model.encoder(input_features)
    enc_hidden = encoder_outputs.last_hidden_state  # (1, 1500, 384)

print(
    f"encoder out: {tuple(enc_hidden.shape)}  "
    f"min={float(enc_hidden.min()):.4f} max={float(enc_hidden.max()):.4f} "
    f"mean={float(enc_hidden.mean()):.4f}"
)

# Whisper's encoder hidden width matches d_model. Sanity check vs tiny config.
assert enc_hidden.shape == (1, 1500, 384), f"unexpected encoder shape {enc_hidden.shape}"

# Write row-major (n_audio_ctx, d_model) f32 LE — exactly what the Rust
# `WhisperDecoder::prepare_audio_context` consumes and what
# `WhisperEncoder::forward` returns.
enc_np = enc_hidden[0].cpu().numpy().astype(np.float32, copy=False)
enc_np.tofile(str(ENC_REF))
print(f"wrote {ENC_REF} ({ENC_REF.stat().st_size} bytes = 1500*384*4 = {1500*384*4})")

# ── 3. Step-0 decoder logits ──────────────────────────────────────────────
# We feed the canonical English-transcribe prefix, identical to what the
# Rust smoke test will replay:
#   <|startoftranscript|> <|en|> <|transcribe|> <|notimestamps|>
# Token IDs come from the model's tokenizer; pin them so the smoke test
# can hard-code the same prefix without loading a tokenizer.
tokenizer = processor.tokenizer
sot_id = tokenizer.convert_tokens_to_ids("<|startoftranscript|>")
lang_id = tokenizer.convert_tokens_to_ids("<|en|>")
task_id = tokenizer.convert_tokens_to_ids("<|transcribe|>")
notim_id = tokenizer.convert_tokens_to_ids("<|notimestamps|>")
prefix = [sot_id, lang_id, task_id, notim_id]
print(f"forced prefix tokens: {prefix}")

# Step-0 == feed the SOT alone, conditioned on encoder hidden state.
# This is the very first decode step, the one most directly comparable
# to a Rust `decoder.decode_step(<sot>, 0)` call after
# `prepare_audio_context(enc_hidden)`.
sot_in = torch.tensor([[sot_id]], dtype=torch.long)
with torch.no_grad():
    out = model(
        decoder_input_ids=sot_in,
        encoder_outputs=encoder_outputs,
        return_dict=True,
    )
    step0_logits = out.logits[0, -1, :].cpu().numpy().astype(np.float32)
print(
    f"step-0 logits: shape={step0_logits.shape} "
    f"min={float(step0_logits.min()):.4f} max={float(step0_logits.max()):.4f} "
    f"argmax={int(step0_logits.argmax())}"
)
step0_logits.tofile(str(LOGITS_REF))
print(f"wrote {LOGITS_REF} ({LOGITS_REF.stat().st_size} bytes)")

# ── 4. First N generated token IDs (greedy) ───────────────────────────────
# Use HF's generate with the same forced decoder prefix. We disable
# sampling, beams, and temperature so the result is deterministic and
# directly comparable to a Rust greedy argmax loop.
forced_decoder_ids = [
    (1, lang_id),
    (2, task_id),
    (3, notim_id),
]
gen_kwargs = dict(
    max_new_tokens=N_GENERATED_TOKENS,
    num_beams=1,
    do_sample=False,
    forced_decoder_ids=forced_decoder_ids,
)
with torch.no_grad():
    generated = model.generate(input_features, **gen_kwargs)
gen_ids = generated[0].cpu().numpy().astype(np.uint32)
print(
    f"generated {len(gen_ids)} tokens (incl. prefix): "
    f"first 8 = {gen_ids[:8].tolist()}"
)

# Trim to exactly N tokens after the SOT slot — what the Rust smoke test
# will compare against. Pad with the EOT id if HF stopped early.
eot_id = tokenizer.convert_tokens_to_ids("<|endoftext|>")
if len(gen_ids) < N_GENERATED_TOKENS:
    pad = np.full(N_GENERATED_TOKENS - len(gen_ids), eot_id, dtype=np.uint32)
    gen_ids = np.concatenate([gen_ids, pad])
elif len(gen_ids) > N_GENERATED_TOKENS:
    gen_ids = gen_ids[:N_GENERATED_TOKENS]

gen_ids.tofile(str(TOKENS_REF))
print(f"wrote {TOKENS_REF} ({TOKENS_REF.stat().st_size} bytes = {N_GENERATED_TOKENS}*4)")

# ── 5. Convenience: print the decoded text so a human can eyeball it ──────
text = tokenizer.decode(gen_ids.tolist(), skip_special_tokens=True)
print(f"\nHF decoded text: {text!r}")
print("[done] decoder fixtures regenerated")
